package com.xoxo.pos.accounts;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController @RequestMapping("/api/accounts") public class AccountController{private final AccountRepository repo;private final AccountService service;public AccountController(AccountRepository repo,AccountService service){this.repo=repo;this.service=service;}@GetMapping("/open") public List<Account> open(){return repo.findByStatusOrderByOpenedAtDesc(AccountStatus.OPEN);}@GetMapping("/table/{tableId}/open") public List<Account> tableOpen(@PathVariable Long tableId){return repo.findByBarTableIdAndStatusOrderByOpenedAtAsc(tableId,AccountStatus.OPEN);}@GetMapping("/{id}") public Account get(@PathVariable Long id){return repo.findById(id).orElseThrow();}@PostMapping public Account create(@RequestBody CreateAccountRequest r){return service.create(r);}@PostMapping("/{id}/items") public Account add(@PathVariable Long id,@RequestBody AddAccountItemRequest r){return service.addItem(id,r);}@DeleteMapping("/{id}/items/{itemId}") public Account remove(@PathVariable Long id,@PathVariable Long itemId){return service.removeItem(id,itemId);}@PostMapping("/{id}/pay") public Account pay(@PathVariable Long id,@RequestBody PayAccountRequest r){return service.pay(id,r);}@PostMapping("/{id}/cancel") public Account cancel(@PathVariable Long id){return service.cancel(id);}@PostMapping("/merge") public Account merge(@RequestBody MergeAccountsRequest r){return service.merge(r);}}
